declare
  v_owner_user_id uuid;
  v_collab_user_id uuid;
  v_project_id uuid;
begin
  select id into v_owner_user_id
  from auth.users
  where lower(email) = lower('karnoni@gmail.com')
  limit 1;

  if v_owner_user_id is null then
    raise exception 'Owner user not found in auth.users for email: karnoni@gmail.com';
  end if;

  select id into v_collab_user_id
  from auth.users
  where lower(email) = lower('raz.oferaz@gmail.com')
  limit 1;

  if v_collab_user_id is null then
    raise exception 'Collaborator user not found in auth.users for email: raz.oferaz@gmail.com';
  end if;

  insert into public.profiles (id)
  values (v_owner_user_id), (v_collab_user_id)
  on conflict (id) do nothing;

  select p.id
  into v_project_id
  from public.projects p
  where p.created_by = v_owner_user_id
    and lower(p.name) = lower('Srithanu - Imported')
  order by p.created_at
  limit 1;

  if v_project_id is null then
    insert into public.projects (name, client_name, location, currency, created_by)
    values ('Srithanu - Imported', 'Imported Customer Data', 'Thailand', 'THB', v_owner_user_id)
    returning id into v_project_id;
  else
    update public.projects
    set
      client_name = 'Imported Customer Data',
      location = 'Thailand',
      currency = 'THB',
      updated_at = now()
    where id = v_project_id;
  end if;

  insert into public.project_members (project_id, user_id, role)
  values
    (v_project_id, v_owner_user_id, 'owner'),
    (v_project_id, v_collab_user_id, 'editor')
  on conflict (project_id, user_id) do update
    set role = excluded.role
    where public.project_members.role <> 'owner';

